    leave_id, student_id, counselor_id, leave_type, reason,
    start_time, end_time, status, cancel_reason, approve_reason,
    created_at, updated_at
) VALUES (
    #{leaveId}, #{studentId}, #{counselorId}, #{leaveType}, #{reason},
    #{startTime}, #{endTime}, #{status}, #{cancelReason}, #{approveReason},
    #{createdAt}, #{updatedAt}
)

mapper.select:
SELECT leave_id, student_id, counselor_id, leave_type, reason, start_time, end_time, status, cancel_reason, approve_reason, created_at FROM leave_request
AND student_id = #{query.studentId}
AND status = #{query.statusFilter}
ORDER BY created_at DESC
